"use strict";(globalThis.webpackChunkbarnum_docs=globalThis.webpackChunkbarnum_docs||[]).push([[581],{5610(e){e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"documentationSidebar":[{"type":"link","label":"Introduction","href":"/docs/","docId":"index","unlisted":false},{"type":"link","label":"Quickstart","href":"/docs/quickstart","docId":"quickstart","unlisted":false},{"type":"category","label":"Reference","items":[{"type":"link","label":"Builtins","href":"/docs/reference/builtins","docId":"reference/builtins","unlisted":false},{"type":"link","label":"CLI Reference","href":"/docs/reference/cli","docId":"reference/cli","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Architecture","items":[{"type":"link","label":"Architecture","href":"/docs/architecture/","docId":"architecture/index","unlisted":false},{"type":"link","label":"TypeScript AST","href":"/docs/architecture/typescript-ast","docId":"architecture/typescript-ast","unlisted":false},{"type":"link","label":"Compiler and Execution Model","href":"/docs/architecture/compiler","docId":"architecture/compiler","unlisted":false},{"type":"link","label":"Algebraic Effect Handlers","href":"/docs/architecture/algebraic-effect-handlers","docId":"architecture/algebraic-effect-handlers","unlisted":false},{"type":"link","label":"Validation","href":"/docs/architecture/validation","docId":"architecture/validation","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Repertoire","items":[{"type":"link","label":"Repertoire","href":"/docs/repertoire/","docId":"repertoire/index","unlisted":false},{"type":"link","label":"Linear Pipeline","href":"/docs/repertoire/linear-pipeline","docId":"repertoire/linear-pipeline","unlisted":false},{"type":"link","label":"Branching","href":"/docs/repertoire/branching","docId":"repertoire/branching","unlisted":false},{"type":"link","label":"Branching Refactor","href":"/docs/repertoire/branching-refactor","docId":"repertoire/branching-refactor","unlisted":false},{"type":"link","label":"Fan-Out","href":"/docs/repertoire/fan-out","docId":"repertoire/fan-out","unlisted":false},{"type":"link","label":"Fan-Out with Aggregation","href":"/docs/repertoire/fan-out-finally","docId":"repertoire/fan-out-finally","unlisted":false},{"type":"link","label":"Sequential Processing","href":"/docs/repertoire/sequential","docId":"repertoire/sequential","unlisted":false},{"type":"link","label":"Adversarial Review","href":"/docs/repertoire/adversarial-review","docId":"repertoire/adversarial-review","unlisted":false},{"type":"link","label":"Error Recovery","href":"/docs/repertoire/error-recovery","docId":"repertoire/error-recovery","unlisted":false},{"type":"link","label":"Side Effects","href":"/docs/repertoire/hooks","docId":"repertoire/hooks","unlisted":false},{"type":"link","label":"Schema Validation","href":"/docs/repertoire/validation","docId":"repertoire/validation","unlisted":false},{"type":"link","label":"Deterministic Steps","href":"/docs/repertoire/commands","docId":"repertoire/commands","unlisted":false},{"type":"link","label":"Code Review","href":"/docs/repertoire/code-review","docId":"repertoire/code-review","unlisted":false},{"type":"link","label":"Legal Review","href":"/docs/repertoire/legal-review","docId":"repertoire/legal-review","unlisted":false},{"type":"link","label":"Document Verification","href":"/docs/repertoire/document-verification","docId":"repertoire/document-verification","unlisted":false},{"type":"link","label":"Editing Assistant","href":"/docs/repertoire/editing-assistant","docId":"repertoire/editing-assistant","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"architecture/algebraic-effect-handlers":{"id":"architecture/algebraic-effect-handlers","title":"Algebraic Effect Handlers","description":"Barnum\'s control flow combinators \u2014 loop, tryCatch, earlyReturn, race, withTimeout \u2014 are all implemented using the same substrate: algebraic effect handlers. This is not a metaphor. The AST has dedicated Handle and Perform nodes, the runtime has a frame-based handler stack, and effects propagate by walking the ancestor chain \u2014 the same architecture you\'d find in a language designed around algebraic effects.","sidebar":"documentationSidebar"},"architecture/compiler":{"id":"architecture/compiler","title":"Compiler and Execution Model","description":"The Rust side of Barnum has two phases: compilation (flatten the tree AST into a linear array) and execution (drive the state machine until the workflow terminates). This page covers both.","sidebar":"documentationSidebar"},"architecture/index":{"id":"architecture/index","title":"Architecture","description":"Barnum is a TypeScript DSL that compiles to a serializable AST, which is executed by a Rust runtime. This separation lets you author workflows in a language with world-class type inference while executing them on a runtime designed for precise control flow, schema validation, and concurrent subprocess management.","sidebar":"documentationSidebar"},"architecture/typescript-ast":{"id":"architecture/typescript-ast","title":"TypeScript AST","description":"Barnum\'s TypeScript library is a DSL that produces a serializable AST. When you write pipe(listFiles, forEach(refactor)), you\'re not scheduling work \u2014 you\'re building a JSON-serializable tree that describes the workflow\'s structure. The Rust runtime receives this tree and executes it.","sidebar":"documentationSidebar"},"architecture/validation":{"id":"architecture/validation","title":"Validation","description":"Barnum uses Zod as a single source of truth for handler contracts. A single Zod schema simultaneously:","sidebar":"documentationSidebar"},"index":{"id":"index","title":"Introduction","description":"Barnum is a programming language for asynchronous programming that is geared towards making it easy to precisely orchestrate agents.","sidebar":"documentationSidebar"},"quickstart":{"id":"quickstart","title":"Quickstart","description":"Install","sidebar":"documentationSidebar"},"reference/builtins":{"id":"reference/builtins","title":"Builtins","description":"Barnum provides a set of built-in combinators for composing workflows. Everything is fully typed \u2014 TypeScript tracks input and output types through the entire pipeline.","sidebar":"documentationSidebar"},"reference/cli":{"id":"reference/cli","title":"CLI Reference","description":"Barnum provides two command-line tools: barnum for running workflows and troupe for managing worker agents.","sidebar":"documentationSidebar"},"repertoire/adversarial-review":{"id":"repertoire/adversarial-review","title":"Adversarial Review","description":"Implement a change, have a separate agent judge it, and loop until the judge approves. The implementing agent never sees the judge\'s full criteria, and the judge never sees the implementation instructions \u2014 each has focused context.","sidebar":"documentationSidebar"},"repertoire/branching":{"id":"repertoire/branching","title":"Branching","description":"Route to different actions based on a tagged union output. An analyzer handler classifies the input, then branch dispatches to the appropriate handler.","sidebar":"documentationSidebar"},"repertoire/branching-refactor":{"id":"repertoire/branching-refactor","title":"Branching Refactor","description":"Route files to specialized refactoring agents based on what each file needs. An analyzer classifies the work, then branch dispatches to the right specialist.","sidebar":"documentationSidebar"},"repertoire/code-review":{"id":"repertoire/code-review","title":"Code Review","description":"Review changed files in parallel with multiple checks per file: coding standards, security, performance. Each check runs independently with focused instructions.","sidebar":"documentationSidebar"},"repertoire/commands":{"id":"repertoire/commands","title":"Deterministic Steps","description":"Not every step needs an LLM. Use regular TypeScript handlers for deterministic operations: listing files, running builds, calling APIs, committing changes. Save the agent for the parts that require judgment.","sidebar":"documentationSidebar"},"repertoire/document-verification":{"id":"repertoire/document-verification","title":"Document Verification","description":"Extract verifiable claims from a document, then fact-check each one independently in parallel.","sidebar":"documentationSidebar"},"repertoire/editing-assistant":{"id":"repertoire/editing-assistant","title":"Editing Assistant","description":"Run multiple independent writing analyses in parallel. Each check focuses on one dimension of quality.","sidebar":"documentationSidebar"},"repertoire/error-recovery":{"id":"repertoire/error-recovery","title":"Error Recovery","description":"Catch failures and route to a recovery handler instead of crashing the workflow.","sidebar":"documentationSidebar"},"repertoire/fan-out":{"id":"repertoire/fan-out","title":"Fan-Out","description":"Split one task into multiple parallel tasks. Each element of an array is processed independently and concurrently.","sidebar":"documentationSidebar"},"repertoire/fan-out-finally":{"id":"repertoire/fan-out-finally","title":"Fan-Out with Aggregation","description":"Run work in parallel, then follow up with a single step after everything completes. In Barnum, this is just a pipe \u2014 the step after forEach waits for all parallel work to finish.","sidebar":"documentationSidebar"},"repertoire/hooks":{"id":"repertoire/hooks","title":"Side Effects","description":"Run actions for side effects without changing the pipeline value. Use tap to log progress, write metrics, or perform cleanup while passing the original input through.","sidebar":"documentationSidebar"},"repertoire/index":{"id":"repertoire/index","title":"Repertoire","description":"Each pattern below is a self-contained workflow you can copy, adapt, and combine.","sidebar":"documentationSidebar"},"repertoire/legal-review":{"id":"repertoire/legal-review","title":"Legal Review","description":"Fan out a contract review into parallel specialist analyses, then synthesize a final recommendation.","sidebar":"documentationSidebar"},"repertoire/linear-pipeline":{"id":"repertoire/linear-pipeline","title":"Linear Pipeline","description":"Process data through a sequence of steps, where each step\'s output becomes the next step\'s input.","sidebar":"documentationSidebar"},"repertoire/sequential":{"id":"repertoire/sequential","title":"Sequential Processing","description":"Process items one at a time, in order. Use this when each step must see the result of the previous one \u2014 for example, applying multiple database migrations or making ordered changes to the same file.","sidebar":"documentationSidebar"},"repertoire/validation":{"id":"repertoire/validation","title":"Schema Validation","description":"Validate handler inputs and outputs with Zod schemas. Barnum compiles schemas into JSON Schema validators at workflow init and enforces them at every handler boundary.","sidebar":"documentationSidebar"}}}')}}]);